// npm install @anthropic-ai/sdk

const Anthropic = require('@anthropic-ai/sdk')
const fetch = require('node-fetch')

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY
})

async function gerarTarefasComClaude() {
  // 1. Busca tarefas do seu banco
  const response = await fetch('http://localhost:3000/api/ia/analisar-progresso', {
    method: 'POST'
  })
  const dados = await response.json()

  // 2. Formata para Claude
  const prompt = `
Você é um assistente educacional. Baseado nesse progresso de estudos:

Total de tarefas: ${dados.dados.total}
Concluídas: ${dados.dados.concluidas}
Progresso: ${dados.dados.percentual}%

Por matéria:
${dados.dados.por_materia.map(m => `- ${m.materia}: ${m.feitas}/${m.total}`).join('\\n')}

Gere 3-5 novas tarefas de estudo prioritárias em JSON:
[
  {
    "descricao": "...",
    "materia": "...",
    "tipo": "tarefa|prova|estudo",
    "prioridade": "alta|normal|baixa",
    "data_vencimento": "YYYY-MM-DD"
  }
]
  `

  // 3. Chama Claude
  const message = await client.messages.create({
    model: 'claude-3-opus-20250204',
    max_tokens: 1024,
    messages: [
      {
        role: 'user',
        content: prompt
      }
    ]
  })

  // 4. Extrai JSON da resposta
  const textoResposta = message.content[0].text
  const match = textoResposta.match(/\[\s*{[\s\S]*}\s*\]/)

  if (!match) {
    console.error('Claude não retornou JSON válido')
    return
  }

  const tarefasGeradas = JSON.parse(match[0])

  // 5. Envia para sua API
  const respostaAPI = await fetch('http://localhost:3000/api/ia/gerar-tarefas', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      modelo: 'claude-3-opus',
      origem: 'geracao_automatica',
      tarefas: tarefasGeradas
    })
  })

  const resultado = await respostaAPI.json()
  console.log(`✅ ${resultado.criadas} tarefas criadas via Claude!`)
}

gerarTarefasComClaude()
